    const initialCost = (0 + 1) * (0 + 1);
    dp[0][0][1] = initialCost;

    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        enqueue(cost, i, j, parity) {
            const node = [cost, i, j, parity];
            this.heap.push(node);
            this.heapifyUp(this.heap.length - 1);
        }
        dequeue() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.heapifyDown(0);
            return min;
        }
        heapifyUp(index) {
            let parent = Math.floor((index - 1) / 2);
            while (index > 0 && this.heap[index][0] < this.heap[parent][0]) {
                [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                index = parent;
                parent = Math.floor((index - 1) / 2);
            }
        }
        heapifyDown(index) {
            const left = 2 * index + 1;
            const right = 2 * index + 2;
            let smallest = index;
            if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]) {
                smallest = left;
            }
            if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]) {
                smallest = right;
            }
            if (smallest !== index) {
                [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                this.heapifyDown(smallest);
            }
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.enqueue(initialCost, 0, 0, 1);

    const dirs = [[0, 1], [1, 0]];

    while (!pq.isEmpty()) {
        const [cost, i, j, p] = pq.dequeue();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dp[i][j][p]) {
            continue;
        }

        if (p === 1) {
            if (j + 1 < n) {
                const ni = i;
                const nj = j + 1;
                const newCost = cost + (ni + 1) * (nj + 1);
                if (newCost < dp[ni][nj][0]) {
                    dp[ni][nj][0] = newCost;
                    pq.enqueue(newCost, ni, nj, 0);
                }
            }
            if (i + 1 < m) {
                const ni = i + 1;
                const nj = j;
                const newCost = cost + (ni + 1) * (nj + 1);
                if (newCost < dp[ni][nj][0]) {
                    dp[ni][nj][0] = newCost;
                    pq.enqueue(newCost, ni, nj, 0);
                }
            }
