import java.util.*

data class State(val cost: Long, val i: Int, val j: Int, val parity: Int) : Comparable<State> {
    override fun compareTo(other: State): Int {
        return this.cost.compareTo(other.cost)
    }
}

fun solve(m: Long, n: Long, waitCost: Array<Array<Long>>): Long {
    val INF = Long.MAX_VALUE
    val dp = Array(m.toInt()) { row ->
        Array(n.toInt()) { col ->
            Array(2) { INF }
        }
    }
    val initialCost = (0 + 1) * (0 + 1)
    dp[0][0][1] = initialCost

    val pq = PriorityQueue<State>()
    pq.add(State(initialCost, 0, 0, 1))

    val dirs = arrayOf(intArrayOf(0, 1), intArrayOf(1, 0))

    while (!pq.isEmpty()) {
        val state = pq.poll()
        val cost = state.cost
        val i = state.i
        val j = state.j
        val parity = state.parity

        if (i == m.toInt() - 1 && j == n.toInt() - 1) {
            return cost
        }

        if (cost > dp[i][j][parity]) {
            continue
        }

        if (parity == 1) {
            for (dir in dirs) {
                val ni = i + dir[0]
